{
  decorators: [Story => <Story />],
  args: {
    ...defaultArgs,
    title: "This is a title placeholder for a card which has a maximum line length on two lines."
  },
  argTypes: {
    isCentered: {
      description: "If the content is centered",
      control: "boolean"
    },
    density: {
      description: "The density of the card",
      control: "select",
      options: Object.values(CardDensity)
    },
    positionPicto: {
      description: "The position of the picto",
      control: "select",
      options: ["left", "right"]
    }
  },
  render: args => {
    const isDark = useDarkMode();
    const customImageClasses = cn({
      [styles.dark]: isDark,
      [styles.light]: !isDark
    });
    return <Card {...args} type={CardType.LIST}>
        {args.positionPicto === "left" && <Card.MediaCustom isCentered={args.isCentered}>
            <Image src={clinical} alt="Sanofi's latest healthcare initiative visual" className={customImageClasses} />
          </Card.MediaCustom>}
        <Card.Section>
          <Card.Content category="Eyebrow One (i.e Category)" date="Eyebrow Two (i.e Date)" title={<Title variant={args.titleSize}>{args.title}</Title>} subText="Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore" buttonSlot={args.withButtonIcon && <Card.Button icon={IconName.MORE_VERT} onClick={() => notify(args)} aria-label="More actions Card List Picto View" />} />
          <Card.Action>
            <LinkStandalone href={sanofiUrl} size={LinkSize.SMALL}>
              Standalone link
            </LinkStandalone>
          </Card.Action>
        </Card.Section>

        {args.positionPicto === "right" && <Card.MediaCustom isCentered={args.isCentered} endSide>
            <Image src={clinical} alt="Infographic representing Sanofi's impact on global health" />
          </Card.MediaCustom>}
      </Card>;
  }
}
